import numpy as np


class Solver:
    def __init__(self):
        self._out = None
        self._n = 0

    def solve(self, problem, **kwargs):
        vec1, vec2 = problem
        n = len(vec1)
        if self._n != n:
            self._out = np.empty((n, n), dtype=np.float64)
            self._n = n
        np.outer(vec1, vec2, out=self._out)
        return self._out
